import React, { useState } from "react";

function App() {

  const [hcpName, setHcpName] = useState("");
  const [interactionType, setInteractionType] = useState("");
  const [date, setDate] = useState("");
  const [topics, setTopics] = useState("");
  const [sentiment, setSentiment] = useState("");
  const [followUp, setFollowUp] = useState("");
  const [aiText, setAiText] = useState("");

  const logInteraction = () => {

    const data = {
      hcpName,
      interactionType,
      date,
      topics,
      sentiment,
      followUp
    };

    console.log("Logged Interaction:", data);

    alert("Interaction Logged! Check console.");
  };


  const askAI = async () => {

    const response = await fetch("http://127.0.0.1:8000/ai-log", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        text: aiText
      })
    });

    const data = await response.json();

    setHcpName(data.hcpName);
    setInteractionType(data.interactionType);
    setTopics(data.topics);
    setSentiment(data.sentiment);
    setFollowUp(data.followUp);
  };


  return (
    <div style={page}>

      <div style={container}>

        {/* LEFT SIDE FORM */}

        <div style={formCard}>

          <h2 style={{marginBottom:"20px"}}>Log HCP Interaction</h2>

          <input
            placeholder="HCP Name"
            style={input}
            value={hcpName}
            onChange={(e)=>setHcpName(e.target.value)}
          />

          <select
            style={input}
            value={interactionType}
            onChange={(e)=>setInteractionType(e.target.value)}
          >
            <option value="">Interaction Type</option>
            <option>Meeting</option>
            <option>Call</option>
          </select>


          <div style={row}>

            <input
              type="date"
              style={input}
              value={date}
              onChange={(e)=>setDate(e.target.value)}
            />

            <input
              type="time"
              style={input}
            />

          </div>


          <input
            placeholder="Attendees"
            style={input}
          />


          <textarea
            placeholder="Topics Discussed"
            style={input}
            value={topics}
            onChange={(e)=>setTopics(e.target.value)}
          />


          <textarea
            placeholder="Materials Shared"
            style={input}
          />


          <textarea
            placeholder="Samples Distributed"
            style={input}
          />


          {/* Sentiment */}

          <div style={radioGroup}>

            <label>
              <input
                type="radio"
                name="sentiment"
                value="Positive"
                onChange={(e)=>setSentiment(e.target.value)}
              /> Positive
            </label>

            <label>
              <input
                type="radio"
                name="sentiment"
                value="Neutral"
                onChange={(e)=>setSentiment(e.target.value)}
              /> Neutral
            </label>

            <label>
              <input
                type="radio"
                name="sentiment"
                value="Negative"
                onChange={(e)=>setSentiment(e.target.value)}
              /> Negative
            </label>

          </div>


          <textarea
            placeholder="Outcomes"
            style={input}
          />


          <textarea
            placeholder="Follow-up Actions"
            style={input}
            value={followUp}
            onChange={(e)=>setFollowUp(e.target.value)}
          />


          <button style={button} onClick={logInteraction}>
            Log Interaction
          </button>

        </div>



        {/* AI ASSISTANT */}

        <div style={aiCard}>

          <h3>AI Assistant</h3>

          <p style={{color:"#aaa"}}>
            Log interaction via chat
          </p>

          <textarea
            placeholder="Example: Met Dr Sharma and discussed Product X..."
            style={chat}
            value={aiText}
            onChange={(e)=>setAiText(e.target.value)}
          />

          <button style={aiButton} onClick={askAI}>
            Ask AI
          </button>

        </div>

      </div>

    </div>
  );
}


/* PAGE */

const page = {
  height:"100vh",
  display:"flex",
  justifyContent:"center",
  alignItems:"center",
  background:"#0f0f0f",
  fontFamily:"Inter, sans-serif"
};


const container = {
  display:"flex",
  gap:"40px"
};


/* FORM CARD */

const formCard = {
  width:"450px",
  padding:"30px",
  borderRadius:"16px",
  background:"#181818",
  boxShadow:"0 0 40px rgba(0,0,0,0.8)",
  color:"white"
};


/* AI CARD */

const aiCard = {
  width:"360px",
  padding:"25px",
  borderRadius:"16px",
  background:"#181818",
  boxShadow:"0 0 40px rgba(0,0,0,0.8)",
  color:"white",
  height:"fit-content"
};


const row = {
  display:"flex",
  gap:"10px"
};


const radioGroup = {
  display:"flex",
  gap:"20px",
  marginBottom:"15px"
};


/* INPUT */

const input = {
  width:"100%",
  padding:"12px",
  marginBottom:"15px",
  borderRadius:"8px",
  border:"1px solid #333",
  background:"#111",
  color:"white"
};


/* BUTTON */

const button = {
  width:"100%",
  padding:"12px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#ff4d6d,#ff758c)",
  color:"white",
  fontSize:"15px",
  cursor:"pointer"
};


const aiButton = {
  width:"100%",
  padding:"12px",
  marginTop:"10px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#00c6ff,#0072ff)",
  color:"white",
  cursor:"pointer"
};


const chat = {
  width:"100%",
  height:"150px",
  padding:"10px",
  borderRadius:"8px",
  border:"1px solid #333",
  background:"#111",
  color:"white",
  marginTop:"10px"
};

export default App;
